ens.vue\n// module chunks = 150","<template>\r\n    <div v-loading=\"ordenLoading\">\r\n        <div>\r\n            <div\r\n                v-if=\"screenWidth > 600\"\r\n                class=\"d-flex flex-wrap justify-content-between\"\r\n            >\r\n                <div\r\n                    v-for=\"(option, idx) in optionsMenu\"\r\n                    :key=\"idx\"\r\n                    v-show=\"option.visible\"\r\n                >\r\n                    <div\r\n                        v-if=\"option.visible\"\r\n                        @click=\"trigerFunction(option.id)\"\r\n                        class=\"\r\n              m-1\r\n              btn btn-light\r\n              rounded\r\n              d-flex\r\n              flex-column\r\n              align-items-center\r\n              justify-content-center\r\n            \"\r\n                        style=\"min-width: 120px; min-height: 75px\"\r\n                    >\r\n                        <div class=\"text-center\" style=\"margin-bottom: 2px\">\r\n                            <p\r\n                                style=\"margin: 0 !important; padding: 0 !important\"\r\n                                v-for=\"(title, idx2) in option.title\"\r\n                                :key=\"idx2\"\r\n                            >\r\n                                {{ title }}\r\n                            </p>\r\n                        </div>\r\n                        <div>\r\n                            <label\r\n                                v-if=\"option.id == 4\"\r\n                                style=\"margin-left: 2px\"\r\n                                >{{ ordenInBox.length }}</label\r\n                            >\r\n                            <label\r\n                                v-if=\"option.id == 5\"\r\n                                style=\"margin-left: 2px\"\r\n                                >{{ ordensPending }}</label\r\n                            >\r\n                            <i :class=\"option.icon\"> </i>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n            <!-- <div v-if=\"screenWidth < 600\" class=\"d-flex flex-wrap\">\r\n                <div\r\n                    v-for=\"(option, idx) in optionsMenu\"\r\n                    :key=\"idx\"\r\n                    v-show=\"option.visible\"\r\n                >\r\n                    <div\r\n                        v-if=\"option.visible && option.id != 5\"\r\n                        @click=\"trigerFunction(option.id)\"\r\n                        class=\"\r\n              m-1\r\n              btn btn-light\r\n              rounded\r\n              d-flex\r\n              flex-column\r\n              align-items-center\r\n              justify-content-center\r\n            \"\r\n                        style=\"max-width: 60px; max-height: 60px\"\r\n                    >\r\n                        <div\r\n                            class=\"text-center\"\r\n                            style=\"margin-bottom: 2px\"\r\n                        ></div>\r\n                        <div>\r\n                            <label\r\n                                v-if=\"option.id == 4\"\r\n                                style=\"margin-left: 2px\"\r\n                                >{{ ordenInBox.length }}</label\r\n                            >\r\n\r\n                            <i :class=\"[option.icon]\"> </i>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n            </div> -->\r\n            <div\r\n                class=\"bg-primary align-items-center rounded-top\"\r\n                style=\"padding-top: 12px\"\r\n            >\r\n                <div class=\"row col-12\" v-if=\"clientTableData.table\">\r\n                    <div>\r\n                        <h3 class=\"text-white\">\r\n                            <strong style=\"padding-left: 20px\">\r\n                  